//! # AEON — OmegA Layer 2: Cognitive Operating System
//!
//! AEON is the cognitive OS layer. It manages the Phylactery identity chain,
//! constructs and owns the TaskStateObject, and orchestrates the four-phase
//! task execution (ANCHOR → SKELETON → GROUND → FLESH → VERIFY).
//!
//! ## Formal role
//! AEON owns τ_t (TaskStateObject) and Φ_t (Phylactery) in the unified
//! state vector Ω_t = ⟨Φ_t, E_t, τ_t, B_t, S_t, G_t^mem⟩.

use serde::{Deserialize, Serialize};
use chrono::{DateTime, Utc};
use uuid::Uuid;
use std::collections::HashMap;

/// Goal valence vector — preference weights across five dimensions.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GoalValence {
    pub truth: f64,
    pub speed: f64,
    pub safety: f64,
    pub continuity: f64,
    pub operator_preference: f64,
}

impl Default for GoalValence {
    fn default() -> Self {
        Self {
            truth: 1.0,
            speed: 0.4,
            safety: 0.9,
            continuity: 0.8,
            operator_preference: 0.7,
        }
    }
}

/// Phase state of the task execution machine.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub enum PhaseState {
    Anchor,
    Skeleton,
    Ground,
    Flesh,
    Verify,
    Repair,
    Refuse,
}

impl PhaseState {
    pub fn as_str(&self) -> &'static str {
        match self {
            PhaseState::Anchor => "anchor",
            PhaseState::Skeleton => "skeleton",
            PhaseState::Ground => "ground",
            PhaseState::Flesh => "flesh",
            PhaseState::Verify => "verify",
            PhaseState::Repair => "repair",
            PhaseState::Refuse => "refuse",
        }
    }
}

/// TaskStateObject (τ_t) — formal specification of the current goal.
///
/// Owned by AEON. The authoritative record of what success looks like
/// and where we are in achieving it.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TaskStateObject {
    pub task_id: String,
    pub objective: String,
    pub constraints: Vec<String>,
    pub success_criteria: Vec<String>,
    pub declared_unknowns: Vec<String>,
    pub urgency: String,
    pub intent_priority_score: f64,
    pub goal_valence: GoalValence,
    pub authority_shrink_level: f64,
    pub canon_anchor_weight: f64,
    pub predicted_failure_modes: Vec<String>,
    pub phase: PhaseState,
    pub created_at: DateTime<Utc>,
}

impl TaskStateObject {
    pub fn new(objective: impl Into<String>) -> Self {
        Self {
            task_id: Uuid::new_v4().to_string(),
            objective: objective.into(),
            constraints: vec![],
            success_criteria: vec!["accurate response".into(), "relevant to query".into()],
            declared_unknowns: vec![],
            urgency: "normal".into(),
            intent_priority_score: 0.7,
            goal_valence: GoalValence::default(),
            authority_shrink_level: 1.0,
            canon_anchor_weight: 0.5,
            predicted_failure_modes: vec![],
            phase: PhaseState::Anchor,
            created_at: Utc::now(),
        }
    }

    /// Advance to the next phase in the execution machine.
    pub fn advance_phase(&mut self) {
        self.phase = match self.phase {
            PhaseState::Anchor => PhaseState::Skeleton,
            PhaseState::Skeleton => PhaseState::Ground,
            PhaseState::Ground => PhaseState::Flesh,
            PhaseState::Flesh => PhaseState::Verify,
            PhaseState::Verify => PhaseState::Flesh, // stays until accepted
            PhaseState::Repair => PhaseState::Verify,
            PhaseState::Refuse => PhaseState::Refuse,
        };
    }
}

/// IdentityCommit — a single entry in the append-only Phylactery chain.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct IdentityCommit {
    pub timestamp: DateTime<Utc>,
    pub authority: String,
    pub change: String,
    pub signature: Option<String>,
}

/// Phylactery (Φ_t) — append-only identity canon chain.
///
/// Owned by AEON. Maintains the commit history and identity vector
/// across all sessions. This is the authoritative record of "who we are
/// and how we got here."
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Phylactery {
    pub identity_vector: String,
    pub commit_chain: Vec<IdentityCommit>,
    pub current_anchor: Option<String>,
    pub last_updated: DateTime<Utc>,
    pub session_count: u64,
}

impl Phylactery {
    pub fn new(identity_vector: impl Into<String>) -> Self {
        Self {
            identity_vector: identity_vector.into(),
            commit_chain: vec![],
            current_anchor: None,
            last_updated: Utc::now(),
            session_count: 0,
        }
    }

    /// Append a new commit to the chain.
    pub fn commit(&mut self, authority: impl Into<String>, change: impl Into<String>) {
        self.commit_chain.push(IdentityCommit {
            timestamp: Utc::now(),
            authority: authority.into(),
            change: change.into(),
            signature: None,
        });
        self.last_updated = Utc::now();
    }

    /// Compute a simple coherence score based on chain consistency.
    pub fn coherence_score(&self) -> f64 {
        if self.commit_chain.is_empty() {
            return 0.5;
        }
        // TODO: wire to full κ_continuity computation from AEON paper
        let chain_depth = (self.commit_chain.len() as f64).min(10.0) / 10.0;
        0.5 + chain_depth * 0.5
    }
}

/// AEON task lifecycle stage index.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AeonStage {
    Initialize,
    ContextBind,
    PlanGenerate,
    Execute,
    Verify,
    Commit,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_task_phase_progression() {
        let mut task = TaskStateObject::new("Test objective");
        assert_eq!(task.phase, PhaseState::Anchor);
        task.advance_phase();
        assert_eq!(task.phase, PhaseState::Skeleton);
        task.advance_phase();
        assert_eq!(task.phase, PhaseState::Ground);
    }

    #[test]
    fn test_phylactery_coherence_grows_with_commits() {
        let mut p = Phylactery::new("RY::OmegA::v1");
        let base = p.coherence_score();
        p.commit("system", "session start");
        p.commit("operator", "context loaded");
        assert!(p.coherence_score() > base);
    }
}
