//! # ADCCL — OmegA Layer 3: Anti-Drift Cognitive Control Loop
//!
//! ADCCL enforces coherence between task intent and generated outputs.
//! Every claim produced by the LLM is tagged with a grounding label, scored
//! for drift, and gated by a claim budget before the response is committed.
//!
//! ## Formal role
//! ADCCL owns E_t (EconomyState) and computes:
//! - `J_drift`: the aggregate drift penalty across all claims
//! - `V`: the verification score (passes gate when V > τ_verify)
//! - `ClaimBudget`: neuro-credit ledger capping spending per session

use serde::{Deserialize, Serialize};
use chrono::{DateTime, Utc};
use std::collections::HashMap;

/// Grounding label for a single claim.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum GroundingLabel {
    /// Claim has direct evidence in retrieved context
    Supported,
    /// Claim derived via valid inference from supported claims
    Computed,
    /// Claim is speculative but clearly labeled as such
    Hypothetical,
    /// Claim cannot be grounded — triggers drift penalty
    Unsupported,
}

impl GroundingLabel {
    /// Drift cost for this grounding label.
    pub fn drift_cost(&self) -> f64 {
        match self {
            GroundingLabel::Supported => 0.0,
            GroundingLabel::Computed => 0.05,
            GroundingLabel::Hypothetical => 0.10,
            GroundingLabel::Unsupported => 0.25,
        }
    }
}

/// A single tagged claim from a response.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Claim {
    pub claim_id: String,
    pub text: String,
    pub grounding: GroundingLabel,
    pub drift_score: f64,
    pub evidence_refs: Vec<String>,
    pub created_at: DateTime<Utc>,
}

impl Claim {
    pub fn new(text: impl Into<String>, grounding: GroundingLabel) -> Self {
        let drift_score = grounding.drift_cost();
        Self {
            claim_id: uuid::Uuid::new_v4().to_string(),
            text: text.into(),
            grounding,
            drift_score,
            evidence_refs: vec![],
            created_at: Utc::now(),
        }
    }
}

/// GoalContract — formal binding of task intent to verification criteria.
///
/// The GoalContract is the central document that ADCCL uses to verify
/// whether a proposed response is aligned with the original task objective.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GoalContract {
    pub task_id: String,
    pub objective: String,
    pub verification_criteria: Vec<String>,
    pub drift_tolerance: f64,   // maximum J_drift before rejection
    pub tau_verify: f64,        // minimum V to pass verification gate
    pub created_at: DateTime<Utc>,
}

impl GoalContract {
    pub fn new(task_id: impl Into<String>, objective: impl Into<String>) -> Self {
        Self {
            task_id: task_id.into(),
            objective: objective.into(),
            verification_criteria: vec![],
            drift_tolerance: 0.3,
            tau_verify: 0.5,
            created_at: Utc::now(),
        }
    }

    pub fn with_criteria(mut self, criteria: Vec<String>) -> Self {
        self.verification_criteria = criteria;
        self
    }
}

/// ClaimBudget (B_t) — neuro-credit ledger for the current session.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ClaimBudget {
    pub available: f64,
    pub spent: f64,
    pub layer_spending: HashMap<String, f64>,
    pub risk_multiplier: f64,
}

impl ClaimBudget {
    pub fn new(initial_credits: f64) -> Self {
        Self {
            available: initial_credits,
            spent: 0.0,
            layer_spending: HashMap::new(),
            risk_multiplier: 1.0,
        }
    }

    pub fn can_afford(&self, cost: f64) -> bool {
        self.available >= cost * self.risk_multiplier
    }

    pub fn spend(&mut self, layer: &str, cost: f64) -> bool {
        let actual_cost = cost * self.risk_multiplier;
        if self.available < actual_cost {
            return false;
        }
        self.available -= actual_cost;
        self.spent += actual_cost;
        *self.layer_spending.entry(layer.to_string()).or_insert(0.0) += actual_cost;
        true
    }
}

/// VerificationResult — output of the ADCCL verification gate.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct VerificationResult {
    pub task_id: String,
    pub verification_score: f64,
    pub drift_score: f64,
    pub recommendation: VerificationRecommendation,
    pub claim_count: usize,
    pub unsupported_count: usize,
    pub verified_at: DateTime<Utc>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum VerificationRecommendation {
    Accept,
    Revise,
    Refuse,
}

/// DriftVerifier — scores a set of claims against a GoalContract.
pub struct DriftVerifier {
    pub tau_verify: f64,
    pub drift_tolerance: f64,
}

impl DriftVerifier {
    pub fn new(tau_verify: f64, drift_tolerance: f64) -> Self {
        Self { tau_verify, drift_tolerance }
    }

    pub fn verify(&self, task_id: &str, claims: &[Claim], contract: &GoalContract) -> VerificationResult {
        let total_drift: f64 = claims.iter().map(|c| c.drift_score).sum();
        let unsupported_count = claims.iter()
            .filter(|c| c.grounding == GroundingLabel::Unsupported)
            .count();

        let verification_score = if claims.is_empty() {
            0.5
        } else {
            let supported_ratio = 1.0 - (unsupported_count as f64 / claims.len() as f64);
            let drift_penalty = (total_drift / claims.len() as f64).min(1.0);
            (supported_ratio - drift_penalty).max(0.0)
        };

        let recommendation = if verification_score >= contract.tau_verify && total_drift <= contract.drift_tolerance {
            VerificationRecommendation::Accept
        } else if verification_score >= 0.3 {
            VerificationRecommendation::Revise
        } else {
            VerificationRecommendation::Refuse
