//! # MYELIN — OmegA Layer 4: Path-Dependent Graph Memory
//!
//! MYELIN implements the path-dependent memory layer. Unlike flat vector
//! stores, MYELIN tracks which retrieval paths have been exercised and
//! reinforces them over time — creating a memory that gets better at
//! retrieving what the agent actually uses.
//!
//! ## Path hardening equation
//! w(e, t+1) = w(e, t) · λ · (1 + α · δ_success(e, t))
//! where:
//! - λ = 0.995 (decay constant per time unit)
//! - α = 0.1 (reinforcement factor)
//! - δ_success ∈ {0, 1}

use serde::{Deserialize, Serialize};
use chrono::{DateTime, Utc};
use std::collections::HashMap;

/// Four storage strata, ordered from hot to cold.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum StratumLevel {
    S1, // Hot — frequently accessed, high plasticity
    S2, // Warm — recently accessed
    S3, // Staging — consolidating
    N1, // Cold — long-term, low plasticity
}

impl StratumLevel {
    pub fn decay_rate(&self) -> f64 {
        match self {
            StratumLevel::S1 => 0.995,
            StratumLevel::S2 => 0.990,
            StratumLevel::S3 => 0.980,
            StratumLevel::N1 => 0.970,
        }
    }
}

/// A single node in the MYELIN memory graph.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MemoryNode {
    pub id: String,
    pub content: String,
    pub stratum: StratumLevel,
    pub importance: f64,
    pub plasticity_weight: f64,
    pub access_count: u64,
    pub last_accessed: DateTime<Utc>,
    pub created_at: DateTime<Utc>,
}

impl MemoryNode {
    pub fn new(id: impl Into<String>, content: impl Into<String>) -> Self {
        Self {
            id: id.into(),
            content: content.into(),
            stratum: StratumLevel::S1,
            importance: 0.5,
            plasticity_weight: 1.0,
            access_count: 0,
            last_accessed: Utc::now(),
            created_at: Utc::now(),
        }
    }

    /// Apply path hardening after a successful retrieval.
    pub fn harden(&mut self, alpha: f64) {
        self.plasticity_weight *= 1.0 + alpha;
        self.access_count += 1;
        self.last_accessed = Utc::now();
    }

    /// Apply decay to plasticity weight.
    pub fn decay(&mut self) {
        let lambda = self.stratum.decay_rate();
        self.plasticity_weight *= lambda;
    }
}

/// A directed edge in the memory graph, representing a retrieval path.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MemoryEdge {
    pub from: String,
    pub to: String,
    pub weight: f64,
    pub traversal_count: u64,
}

/// MYELIN memory graph — the path-dependent graph structure.
///
/// Nodes are memory entries; edges are retrieval patterns weighted
/// by path-dependent reinforcement.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MemoryGraph {
    pub nodes: HashMap<String, MemoryNode>,
    pub edges: HashMap<String, Vec<MemoryEdge>>,  // from_id -> [edges]
    pub total_retrievals: u64,
    pub alpha: f64,  // reinforcement factor
}

impl MemoryGraph {
    pub fn new() -> Self {
        Self {
            nodes: HashMap::new(),
            edges: HashMap::new(),
            total_retrievals: 0,
            alpha: 0.1,
        }
    }

    pub fn insert(&mut self, node: MemoryNode) {
        self.nodes.insert(node.id.clone(), node);
    }

    /// Record a retrieval hit and harden the path.
    pub fn record_hit(&mut self, node_id: &str) {
        if let Some(node) = self.nodes.get_mut(node_id) {
            node.harden(self.alpha);
        }
        self.total_retrievals += 1;
    }

    /// Apply time-based decay to all nodes.
    pub fn apply_decay(&mut self) {
        for node in self.nodes.values_mut() {
            node.decay();
        }
    }

    /// Retrieve top-k nodes by composite score (importance × plasticity_weight).
    pub fn top_k(&self, k: usize) -> Vec<&MemoryNode> {
        let mut scored: Vec<(&MemoryNode, f64)> = self.nodes.values()
            .map(|n| (n, n.importance * n.plasticity_weight))
            .collect();
        scored.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));
        scored.into_iter().take(k).map(|(n, _)| n).collect()
    }
}

impl Default for MemoryGraph {
    fn default() -> Self {
        Self::new()
    }
}

/// Semantic state — tracks retrieval paths exercised in this session.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SemanticState {
    pub queried_paths: Vec<String>,
    pub path_hardening: HashMap<String, f64>,
    pub last_retrieval_results: Option<Vec<String>>,
    pub decay_rate: f64,
}

impl Default for SemanticState {
    fn default() -> Self {
        Self {
            queried_paths: vec![],
            path_hardening: HashMap::new(),
            last_retrieval_results: None,
            decay_rate: 0.995,
        }
    }
}

/// HardeningResult — output of the MYELIN path hardening operation.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct HardeningResult {
    pub paths_updated: usize,
    pub outcome: String,
    pub decay_rate: f64,
    pub updated_weights: HashMap<String, f64>,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_path_hardening_increases_weight() {
        let mut graph = MemoryGraph::new();
        let node = MemoryNode::new("n1", "Paris is the capital of France");
        graph.insert(node);

        let before = graph.nodes["n1"].plasticity_weight;
        graph.record_hit("n1");
        let after = graph.nodes["n1"].plasticity_weight;
        assert!(after > before);
    }

    #[test]
    fn test_top_k_returns_highest_weight_nodes() {
        let mut graph = MemoryGraph::new();
        let mut n1 = MemoryNode::new("n1", "High importance");
        let mut n2 = MemoryNode::new("n2", "Low importance");
        n1.importance = 0.9;
        n2.importance = 0.1;
        graph.insert(n1);
        graph.insert(n2);

        let top = graph.top_k(1);
        assert_eq!(top[0].id, "n1");
    }
}
