//! # omega-metacog — Meta-Cognitive Monitoring Loop
//!
//! Monitors the agent's own reasoning process in real time.
//! Detects when the agent is drifting from its goal, caught in loops,
//! spending too many credits on a single claim, or producing inconsistent
//! outputs across reasoning steps.

use serde::{Deserialize, Serialize};
use chrono::{DateTime, Utc};
use std::collections::VecDeque;

/// A single observation from the meta-cognitive monitor.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MetaObservation {
    pub timestamp: DateTime<Utc>,
    pub signal: MetaSignal,
    pub severity: f64,  // [0.0, 1.0]
    pub context: String,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub enum MetaSignal {
    GoalDrift,           // Current output diverging from original objective
    CreditBurn,          // Spending rate exceeding budget thresholds
    LoopDetected,        // Same reasoning step executed multiple times
    InconsistencyFlag,   // Contradiction between claim and prior output
    AttentionDiffusion,  // Focus scattered across too many sub-goals
    PhaseStall,          // Phase hasn't advanced in expected time
}

/// MetaCogMonitor — sliding window monitor over reasoning signals.
pub struct MetaCogMonitor {
    pub window_size: usize,
    observations: VecDeque<MetaObservation>,
    pub drift_threshold: f64,
}

impl MetaCogMonitor {
    pub fn new(window_size: usize) -> Self {
        Self {
            window_size,
            observations: VecDeque::new(),
            drift_threshold: 0.6,
        }
    }

    pub fn observe(&mut self, signal: MetaSignal, severity: f64, context: impl Into<String>) {
        let obs = MetaObservation {
            timestamp: Utc::now(),
            signal,
            severity,
            context: context.into(),
        };
        self.observations.push_back(obs);
        if self.observations.len() > self.window_size {
            self.observations.pop_front();
        }
    }

    /// Compute the aggregate meta-cognitive health score [0.0 = degraded, 1.0 = healthy].
    pub fn health_score(&self) -> f64 {
        if self.observations.is_empty() {
            return 1.0;
        }
        let avg_severity: f64 = self.observations.iter().map(|o| o.severity).sum::<f64>()
            / self.observations.len() as f64;
        (1.0 - avg_severity).max(0.0)
    }

    /// Returns true if the monitor is flagging a critical drift condition.
    pub fn is_degraded(&self) -> bool {
        self.health_score() < (1.0 - self.drift_threshold)
    }

    /// Returns the most recent high-severity observation if present.
    pub fn top_concern(&self) -> Option<&MetaObservation> {
        self.observations.iter().max_by(|a, b| a.severity.partial_cmp(&b.severity).unwrap())
    }
}
