//! # omega-worldmodel — Causal World Model
//!
//! Maintains a lightweight causal graph of the agent's current understanding
//! of the world. Used for counterfactual reasoning, prediction, and
//! grounding claims against a coherent model of facts and their relationships.

use serde::{Deserialize, Serialize};
use chrono::{DateTime, Utc};
use std::collections::HashMap;

/// A fact in the world model, with a confidence score.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorldFact {
    pub id: String,
    pub statement: String,
    pub confidence: f64,  // [0.0, 1.0]
    pub source: String,
    pub causal_parents: Vec<String>,  // fact IDs this is derived from
    pub created_at: DateTime<Utc>,
}

impl WorldFact {
    pub fn new(statement: impl Into<String>, confidence: f64, source: impl Into<String>) -> Self {
        Self {
            id: uuid::Uuid::new_v4().to_string(),
            statement: statement.into(),
            confidence: confidence.clamp(0.0, 1.0),
            source: source.into(),
            causal_parents: vec![],
            created_at: Utc::now(),
        }
    }
}

/// Prediction — a forward-looking inference from the world model.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Prediction {
    pub id: String,
    pub hypothesis: String,
    pub probability: f64,
    pub supporting_facts: Vec<String>,
    pub made_at: DateTime<Utc>,
}

/// WorldModel — the agent's current causal understanding of its context.
pub struct WorldModel {
    pub facts: HashMap<String, WorldFact>,
    pub predictions: Vec<Prediction>,
    pub coherence_score: f64,
}

impl WorldModel {
    pub fn new() -> Self {
        Self {
            facts: HashMap::new(),
            predictions: vec![],
            coherence_score: 1.0,
        }
    }

    pub fn assert_fact(&mut self, fact: WorldFact) {
        self.facts.insert(fact.id.clone(), fact);
        self.recompute_coherence();
    }

    /// Compute coherence as average confidence of all asserted facts.
    fn recompute_coherence(&mut self) {
        if self.facts.is_empty() {
            self.coherence_score = 1.0;
            return;
        }
        let avg: f64 = self.facts.values().map(|f| f.confidence).sum::<f64>()
            / self.facts.len() as f64;
        self.coherence_score = avg;
    }

    /// Query facts relevant to a query string (simple substring match).
    pub fn query(&self, query: &str) -> Vec<&WorldFact> {
        let q = query.to_lowercase();
        self.facts.values()
            .filter(|f| f.statement.to_lowercase().contains(&q))
            .collect()
    }
}

impl Default for WorldModel {
    fn default() -> Self {
        Self::new()
    }
}
