//! # omega-continuity — Persistent Cross-Session Continuity
//!
//! Manages identity and context persistence across sessions.
//! Reads/writes the canonical session state to durable storage so that
//! the agent can resume where it left off — preserving Phylactery chain,
//! active goals, and memory graph state across reboots.

use serde::{Deserialize, Serialize};
use chrono::{DateTime, Utc};

/// A session snapshot — the serialized state at session end.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SessionSnapshot {
    pub session_id: String,
    pub identity_vector: String,
    pub phylactery_depth: usize,
    pub active_task_id: Option<String>,
    pub memory_node_count: usize,
    pub coherence_score: f64,
    pub snapshotted_at: DateTime<Utc>,
}

impl SessionSnapshot {
    pub fn new(session_id: impl Into<String>, identity_vector: impl Into<String>) -> Self {
        Self {
            session_id: session_id.into(),
            identity_vector: identity_vector.into(),
            phylactery_depth: 0,
            active_task_id: None,
            memory_node_count: 0,
            coherence_score: 1.0,
            snapshotted_at: Utc::now(),
        }
    }
}

/// ContinuityAction — what the continuity engine decided to do on session resume.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum ContinuityAction {
    Resumed,     // Loaded prior session state successfully
    Initialized, // No prior state found — started fresh
    Repaired,    // Prior state had coherence issues — repaired before load
    Refused,     // State was corrupted beyond repair — refused to load
}

/// ContinuityEngine — manages session state persistence.
pub struct ContinuityEngine {
    pub coherence_threshold: f64,
    pub snapshots: Vec<SessionSnapshot>,
}

impl ContinuityEngine {
    pub fn new() -> Self {
        Self {
            coherence_threshold: 0.5,
            snapshots: vec![],
        }
    }

    /// Save a session snapshot.
    pub fn save(&mut self, snapshot: SessionSnapshot) {
        self.snapshots.push(snapshot);
    }

    /// Load the most recent snapshot for a given identity vector.
    pub fn load(&self, identity_vector: &str) -> Option<&SessionSnapshot> {
        self.snapshots.iter()
            .filter(|s| s.identity_vector == identity_vector)
            .max_by_key(|s| s.snapshotted_at)
    }

    /// Determine the appropriate continuity action for a session start.
    pub fn on_session_start(&self, identity_vector: &str) -> ContinuityAction {
        match self.load(identity_vector) {
            None => ContinuityAction::Initialized,
            Some(snap) if snap.coherence_score >= self.coherence_threshold => {
                ContinuityAction::Resumed
            }
            Some(_) => ContinuityAction::Repaired,
        }
    }
}

impl Default for ContinuityEngine {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_new_identity_initializes() {
        let engine = ContinuityEngine::new();
        assert_eq!(
            engine.on_session_start("unknown-identity"),
            ContinuityAction::Initialized
        );
    }

    #[test]
    fn test_known_identity_resumes() {
        let mut engine = ContinuityEngine::new();
        let snap = SessionSnapshot::new("s1", "RY::OmegA::v1");
        engine.save(snap);
        assert_eq!(
            engine.on_session_start("RY::OmegA::v1"),
            ContinuityAction::Resumed
        );
    }
}
