    pub active: bool,
}

impl GaingMember {
    pub fn new(member_id: impl Into<String>, name: impl Into<String>, role: GaingRole) -> Self {
        Self {
            member_id: member_id.into(),
            name: name.into(),
            role,
            capabilities: vec![],
            active: true,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum GaingRole {
    LeadArchitect,   // Claude — primary reasoning, architecture, synthesis
    Researcher,      // Perplexity — live web search, fact retrieval
    Analyst,         // DeepSeek / Gemini — deep analysis, math, code
    Challenger,      // Grok — adversarial testing, edge cases
    Synthesizer,     // Council synthesis — multi-provider consensus
}

/// A task dispatched to a gAIng member.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GaingTask {
    pub task_id: String,
    pub assigned_to: String,
    pub prompt: String,
    pub priority: u8,
    pub dispatched_at: DateTime<Utc>,
    pub completed_at: Option<DateTime<Utc>>,
    pub result: Option<String>,
}

impl GaingTask {
    pub fn new(assigned_to: impl Into<String>, prompt: impl Into<String>) -> Self {
        Self {
            task_id: uuid::Uuid::new_v4().to_string(),
            assigned_to: assigned_to.into(),
            prompt: prompt.into(),
            priority: 5,
            dispatched_at: Utc::now(),
            completed_at: None,
            result: None,
        }
    }

    pub fn complete(mut self, result: impl Into<String>) -> Self {
        self.completed_at = Some(Utc::now());
        self.result = Some(result.into());
        self
    }
}

/// GaingCoordinator — manages the crew roster and task routing.
pub struct GaingCoordinator {
    pub members: HashMap<String, GaingMember>,
    pub task_log: Vec<GaingTask>,
}

impl GaingCoordinator {
    pub fn new() -> Self {
        let mut coord = Self {
            members: HashMap::new(),
            task_log: vec![],
        };
        // Register default crew
        coord.register(GaingMember::new("claude", "Claude", GaingRole::LeadArchitect));
        coord.register(GaingMember::new("perplexity", "Perplexity", GaingRole::Researcher));
        coord.register(GaingMember::new("deepseek", "DeepSeek", GaingRole::Analyst));
        coord.register(GaingMember::new("grok", "Grok", GaingRole::Challenger));
        coord
    }

    pub fn register(&mut self, member: GaingMember) {
        self.members.insert(member.member_id.clone(), member);
    }

    pub fn dispatch(&mut self, task: GaingTask) -> &GaingTask {
        self.task_log.push(task);
        self.task_log.last().unwrap()
    }

    /// Find the best member for a given role.
    pub fn member_by_role(&self, role: GaingRole) -> Option<&GaingMember> {
        self.members.values().find(|m| m.role == role && m.active)
    }

    pub fn active_members(&self) -> Vec<&GaingMember> {
        self.members.values().filter(|m| m.active).collect()
    }
}

impl Default for GaingCoordinator {
    fn default() -> Self {
        Self::new()
    }
}

