        assert!(coord.member_by_role(GaingRole::LeadArchitect).is_some());
        assert!(coord.member_by_role(GaingRole::Researcher).is_some());
        assert!(coord.member_by_role(GaingRole::Analyst).is_some());
        assert!(coord.member_by_role(GaingRole::Challenger).is_some());
    }
}
