async fn test_omega_mode_both_fail_uses_failover() {
    let anthropic: Arc<dyn LlmProvider> = Arc::new(FailingProvider::rate_limited("anthropic"));
    let xai: Arc<dyn LlmProvider> = Arc::new(FailingProvider::rate_limited("xai"));

