    assert_eq!(query_resp.status(), StatusCode::OK);
    let qbody = parse_body(query_resp).await;
    let hits = qbody["hits"].as_array().expect("hits must be array");
    assert!(
        !hits.is_empty(),
        "ingested chunk about quantum should be findable in memory"
    );
}

